import heapq
class TrieAuto:
    def __init__(self):
        self.children = {}
        self.freq = 0
def top_k_suggestions(words, k, prefix):
    root = TrieAuto()
    for term, f in words:
        node = root
        for ch in term:
            node = node.children.setdefault(ch, TrieAuto())
        node.freq += f
    node = root
    for ch in prefix:
        if ch not in node.children:
            return []
        node = node.children[ch]
    heap = []
    def dfs(n, path):
        if n.freq > 0:
            item = (-n.freq, path)
            if len(heap) < k:
                heapq.heappush(heap, item)
            else:
                if item < heap[0]:
                    heapq.heapreplace(heap, item)
        for ch, nxt in n.children.items():
            dfs(nxt, path + ch)
    dfs(node, prefix)
    heap.sort()
    return [term for _, term in heap]

